#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""DOGU UCGEN OKUYUCU - Elazig/Diyarbakir/Sanliurfa videolarindan
%SANIYE'deki beyaz-kutu seridini okur, UCGEN atamasi yapar:
  serit 1. at -> 1. ucgen | serit 2-3 -> 2. ucgen | kalan herkes -> 3. ucgen
GUVENLIK: rakam taniyici GERCEK gliflerden kurulu bankayla calisir;
emin olamadigi kutuda okumaz, o kosuyu ATLAR (sallamaz) ve kirpimi
~/Desktop/dogu_hasat/ klasorune kaydeder (banka buyusun diye).
BATI SISTEMINE DOKUNMAZ - tamamen ayri dosya, ayri cikti (dogu_ucgen.json).
Kullanim: python3 dogu_ucgen_oku.py [max_kosu]   (varsayilan 12)
"""
import base64, io as _io, json, os, re, sys, time, urllib.request

import cv2
import numpy as np

KOK = os.path.dirname(os.path.abspath(__file__))
ARSIV = os.path.join(KOK, "video_lut_arsiv.json")
CIKTI = os.path.join(KOK, "dogu_ucgen.json")
HASAT = os.path.expanduser("~/Desktop/dogu_hasat")
VCACHE = os.path.join(KOK, "dogu_video_cache")
SANIYE = {"ELAZIĞ": 33, "DİYARBAKIR": 24, "ŞANLIURFA": 20}
BAND_X = (0.14, 0.68); BAND_Y = (0.68, 0.92)
GB = (28, 40); ESIK = 0.14; MARJ = 0.025; KNN = 3
URL_RE = re.compile(r"/videoftp/(\d{4})/(\d{1,2})/(\d+)\.mp4\s*$")

BANKA_B64 = ""

def banka_yukle():
    d = np.load(_io.BytesIO(base64.b64decode(BANKA_B64)))
    return {int(k): [x.astype(np.float32) for x in d[k]] for k in d.files}

BANKA = banka_yukle()

# ---------------- kutu bulma (kayan esik) ----------------
def _aday_kutular(maske, W, H):
    konturlar, _ = cv2.findContours(maske, cv2.RETR_EXTERNAL, cv2.CHAIN_APPROX_SIMPLE)
    adaylar = []
    for c in konturlar:
        x, y, w, h = cv2.boundingRect(c)
        if not (W * 0.022 <= w <= W * 0.10): continue
        if not (H * 0.035 <= h <= H * 0.12): continue
        if not (0.5 <= w / float(h) <= 1.9): continue
        if maske[y:y + h, x:x + w].mean() < 130: continue
        adaylar.append((x, y, w, h))
    if not adaylar: return []
    adaylar.sort(key=lambda k: k[0])
    en_iyi = []
    for (x, y, w, h) in adaylar:
        ym = y + h / 2.0
        grup = [k for k in adaylar if abs((k[1] + k[3] / 2.0) - ym) < h * 0.6]
        if len(grup) > len(en_iyi): en_iyi = grup
    en_iyi.sort(key=lambda k: k[0])
    if len(en_iyi) >= 2:              # hayalet filtre: boyu gruptan sapan kutuyu ele
        hh = sorted(k[3] for k in en_iyi)
        med = hh[len(hh) // 2]
        en_iyi = [k for k in en_iyi if abs(k[3] - med) <= med * 0.25]
    return en_iyi[:3]

def kutulari_bul(kare):
    H, W = kare.shape[:2]
    x1, x2 = int(W * BAND_X[0]), int(W * BAND_X[1])
    y1, y2 = int(H * BAND_Y[0]), int(H * BAND_Y[1])
    bolge = kare[y1:y2, x1:x2]
    gri = cv2.cvtColor(bolge, cv2.COLOR_BGR2GRAY)
    en_iyi = []
    for esik in range(230, 129, -10):
        maske = cv2.threshold(gri, esik, 255, cv2.THRESH_BINARY)[1]
        maske = cv2.morphologyEx(maske, cv2.MORPH_CLOSE, np.ones((3, 3), np.uint8))
        grup = _aday_kutular(maske, W, H)
        if len(grup) > len(en_iyi): en_iyi = grup
        if len(en_iyi) == 3: break
    return bolge, en_iyi

# ---------------- rakam tanima (gercek banka + kNN + marj) ----------------
def _norm_glif(g):
    ters = (g < 127).astype(np.uint8)
    ys, xs = np.where(ters > 0)
    if len(xs) < 12: return None
    t = ters[ys.min():ys.max()+1, xs.min():xs.max()+1]
    return cv2.resize(t.astype(np.float32), GB, interpolation=cv2.INTER_AREA)

def _glif_tani(ng):
    skorlar = []
    for d, vs in BANKA.items():
        for v in vs:
            skorlar.append((float(np.mean(np.abs(ng - v))), d))
    skorlar.sort()
    if not skorlar or skorlar[0][0] > ESIK: return None
    oylar = {}
    for s, d in skorlar[:KNN]: oylar[d] = oylar.get(d, 0) + 1
    kazanan = max(oylar, key=oylar.get)
    kaz_en = min(s for s, d in skorlar if d == kazanan)
    dig = [s for s, d in skorlar if d != kazanan]
    if dig and (min(dig) - kaz_en) < MARJ and oylar.get(kazanan, 0) < KNN:
        return None
    return kazanan

def kutu_oku(bolge, kutu, hasat_ad=None):
    x, y, w, h = kutu
    kx = int(w*0.12); ky = int(h*0.10)
    crop = bolge[y+ky:y+h-ky, x+kx:x+w-kx]
    if crop.size == 0: return None
    buyuk = cv2.resize(crop, None, fx=4, fy=4, interpolation=cv2.INTER_CUBIC)
    gri = cv2.cvtColor(buyuk, cv2.COLOR_BGR2GRAY)
    gri = cv2.normalize(gri, None, 0, 255, cv2.NORM_MINMAX)
    ik = cv2.threshold(gri, 0, 255, cv2.THRESH_BINARY + cv2.THRESH_OTSU)[1]
    if ik.mean() < 127: ik = 255 - ik

    def _dene(parcalar):
        if not parcalar or len(parcalar) > 2: return None
        rakamlar = []
        for p in parcalar:
            ng = _norm_glif_mask(p)
            d = _glif_tani(ng) if ng is not None else None
            if d is None: return None
            rakamlar.append(str(d))
        n = int("".join(rakamlar))
        return n if 1 <= n <= 20 else None

    # 1) sutun boslugundan bolme
    ink1 = (ik < 127).astype(np.uint8)
    kol = ink1.sum(axis=0)
    dolu = kol > max(2, ik.shape[0]*0.02)
    sutun, basla = [], None
    for i, v in enumerate(list(dolu) + [False]):
        if v and basla is None: basla = i
        elif not v and basla is not None:
            if i - basla > ik.shape[1]*0.06: sutun.append(ink1[:, basla:i] if False else ink1[:, basla:i])
            basla = None
    sonuc = _dene([p for p in sutun])
    # 2) olmadiysa bagli-bilesen bolmesi (italik ust uste binme icin)
    if sonuc is None:
        n, et, istat, mrk = cv2.connectedComponentsWithStats(ink1, 8)
        ccp = [(mrk[i][0], i) for i in range(1, n) if istat[i][4] > ink1.sum() * 0.12]
        ccp.sort()
        sonuc = _dene([(ink1 * (et == i)).astype(np.uint8) for _, i in ccp])

    if hasat_ad:
        os.makedirs(HASAT, exist_ok=True)
        etiket = str(sonuc) if sonuc is not None else "BILINMIYOR"
        cv2.imwrite(os.path.join(HASAT, "%s_%s.jpg" % (hasat_ad, etiket)), crop)
    return sonuc

def _norm_glif_mask(m):
    ys, xs = np.where(m > 0)
    if len(xs) < 12: return None
    t = m[ys.min():ys.max()+1, xs.min():xs.max()+1]
    return cv2.resize(t.astype(np.float32), GB, interpolation=cv2.INTER_AREA)

def guvenli_indir(url, hedef):
    """once .part'a indir, bitince adlandir - yarim dosya cache'e giremez."""
    gecici = hedef + ".part"
    try:
        urllib.request.urlretrieve(url, gecici)
        os.replace(gecici, hedef)
        return True
    except Exception:
        try: os.remove(gecici)
        except Exception: pass
        return False


def kare_al(video_yol_veya_url, saniye):
    cap = cv2.VideoCapture(video_yol_veya_url)
    if not cap.isOpened(): return None
    fps = cap.get(cv2.CAP_PROP_FPS) or 25
    cap.set(cv2.CAP_PROP_POS_FRAMES, int(saniye * fps))
    ok, kare = cap.read()
    cap.release()
    return kare if ok else None

def serit_oku(video, saniye, hasat_onek):
    for dene, sn in enumerate((saniye, saniye + 4)):
        kare = kare_al(video, sn)
        if kare is None: continue
        bolge, kutular = kutulari_bul(kare)
        if not kutular: continue
        okunan = []
        tamam = True
        for pi, k in enumerate(kutular, 1):
            n = kutu_oku(bolge, k, hasat_ad="%s_sn%d_poz%d" % (hasat_onek, sn, pi))
            if n is None: tamam = False
            else: okunan.append(n)
        if tamam and okunan and len(okunan) == len(set(okunan)):
            return okunan, sn
    return None, None

# ---------------- kosu listesi + kadro (CSV) ----------------
def main():
    maxk = int(sys.argv[1]) if len(sys.argv) > 1 else 12
    import importlib.util
    spec = importlib.util.spec_from_file_location("vgd", os.path.join(KOK, "video_gecmis_doldur.py"))
    vgd = importlib.util.module_from_spec(spec); spec.loader.exec_module(vgd)

    lut = json.load(open(ARSIV, encoding="utf-8"))
    kodlar, _ = vgd.kod_cikar(lut)
    os.makedirs(VCACHE, exist_ok=True)

    eski = {}
    if os.path.exists(CIKTI):
        try: eski = json.load(open(CIKTI, encoding="utf-8"))
        except Exception: eski = {}

    # dogu kosulari: arsivdeki mp4'lerden (tarih, sehir, kosu_no, url)
    kosular = {}
    for k, v in lut.items():
        p = k.split("|")
        if len(p) != 3 or p[2] not in SANIYE: continue
        url = v[0] if isinstance(v, (list, tuple)) else str(v)
        m = URL_RE.search(url)
        if not m: continue
        sehir = p[2]; tarih = p[1]
        kod = kodlar.get(sehir)
        if not kod: continue
        dosya = m.group(3)
        onek6 = dosya[:6]; suf = dosya[6:]
        if not suf.startswith(kod): continue
        kno = suf[len(kod):]
        if not kno.isdigit(): continue
        anahtar = "%s|%s|%s" % (tarih, sehir, int(kno))
        kosular[anahtar] = url

    print("dogu kosusu (arsivde, videolu): %d | bu tur en fazla %d yeni" % (len(kosular), maxk))
    yeni = 0; sonuc = dict(eski)
    csv_cache = {}
    import datetime as _dt
    def _srt(a):
        try:
            return _dt.datetime.strptime(a.split("|")[0], "%d.%m.%Y")
        except Exception:
            return _dt.datetime(1900, 1, 1)
    for anahtar in sorted(kosular, key=_srt, reverse=True):
        if yeni >= maxk: break
        if anahtar in sonuc and sonuc[anahtar].get("serit"): continue
        tarih, sehir, kno = anahtar.split("|"); kno = int(kno)
        url = kosular[anahtar]
        vid = os.path.join(VCACHE, os.path.basename(url))
        kaynak = vid if os.path.exists(vid) else url
        if kaynak == url:
            # once akistan dene; olmazsa indir
            deneme = kare_al(url, SANIYE[sehir])
            if deneme is None:
                if guvenli_indir(url, vid):
                    kaynak = vid
                else:
                    print("  %s: video alinamadi" % anahtar); continue
            else:
                kaynak = url
        onek = "%s_%s_k%d" % (sehir.replace("İ","I").replace("Ğ","G").replace("Ş","S"), tarih.replace(".",""), kno)
        serit, sn = serit_oku(kaynak, SANIYE[sehir], onek)
        if serit is None and kaynak == vid:
            cap = cv2.VideoCapture(vid); bozuk = not cap.isOpened(); cap.release()
            if bozuk:
                try: os.remove(vid)
                except Exception: pass
                if guvenli_indir(url, vid):
                    serit, sn = serit_oku(vid, SANIYE[sehir], onek)
        if serit is None and kaynak == url:
            # akis takildiysa (zaman asimi/yarim dosya) indir ve yeniden dene
            if guvenli_indir(url, vid):
                serit, sn = serit_oku(vid, SANIYE[sehir], onek)
        yeni += 1
        if serit is None:
            print("  %-28s OKUNAMADI (kirpimlar hasata kaydedildi)" % anahtar)
            sonuc[anahtar] = {"serit": None}
            continue
        # kadro (CSV) -> kalan atlar 3. ucgen
        cgun = (tarih, sehir)
        if cgun not in csv_cache:
            import datetime
            d = datetime.datetime.strptime(tarih, "%d.%m.%Y")
            metin = vgd.indir(vgd.csv_url(d, vgd.SEHIR_AD[sehir]))
            csv_cache[cgun] = vgd.csv_kosular(metin) if metin else {}
            time.sleep(0.7)
        atlar = [no for no, _ in (csv_cache[cgun].get(kno) or [])]
        ucgen = {}
        if serit: ucgen[str(serit[0])] = 1
        for n in serit[1:3]: ucgen[str(n)] = 2
        for no in atlar:
            if no not in ucgen: ucgen[no] = 3
        sonuc[anahtar] = {"serit": serit, "sn": sn, "ucgen": ucgen}
        print("  %-28s serit=%-12s ucgen1=%s ucgen2=%s kalan(3.ucgen)=%d at" % (
            anahtar, serit, serit[0], serit[1:3], max(0, len(atlar) - len(serit))))

    json.dump(sonuc, open(CIKTI, "w", encoding="utf-8"), ensure_ascii=False, indent=1)
    ok = sum(1 for v in sonuc.values() if v.get("serit"))
    print("TOPLAM: %d kosu kayitli, %d okundu | cikti: dogu_ucgen.json" % (len(sonuc), ok))
    print("Okunamayanlarin kirpimlari: ~/Desktop/dogu_hasat (zipleyip gonder, bankayi buyuteyim)")
    print("DOGU_UCGEN_OKU_BITTI")

if __name__ == "__main__":
    main()
